+        // min_rtt = 100_000
+        // ack_delay.min(sample - min_rtt) = 100_000.min(0) = 0
+        // adjusted = 100_000 - 0 = 100_000
+        rtt.update(100_000, 100_000);
+        assert_eq!(rtt.smoothed_rtt_micros(), Some(100_000));
